interface WindowEntry {
  timestamps: number[];
}

/**
 * Sliding window rate limiter.
 * Unlike fixed-window counters, this prevents burst traffic at window boundaries.
 * Each request is tracked by timestamp, and only requests within the window are counted.
 */
export function slidingWindowRateLimit(opts: {
  windowMs: number;
  maxRequests: number;
}) {
  const clients = new Map<string, WindowEntry>();

  // Clean up stale entries every minute
  setInterval(() => {
    const cutoff = Date.now() - opts.windowMs;
    for (const [key, entry] of clients) {
      entry.timestamps = entry.timestamps.filter((t) => t > cutoff);
      if (entry.timestamps.length === 0) clients.delete(key);
    }
  }, 60_000);

  return (req: Request, res: Response, next: NextFunction) => {
    const key = req.ip || 'unknown';
    const now = Date.now();
    const cutoff = now - opts.windowMs;

    let entry = clients.get(key);
    if (!entry) {
      entry = { timestamps: [] };
      clients.set(key, entry);
    }

    // Drop timestamps outside the window
    entry.timestamps = entry.timestamps.filter((t) => t > cutoff);

    if (entry.timestamps.length >= opts.maxRequests) {
      const retryAfter = Math.ceil((entry.timestamps[0] + opts.windowMs - now) / 1000);
      res.set('Retry-After', String(retryAfter));
      return res.status(429).json({
        error: 'Too many requests',
        retryAfter,
      });
    }

    entry.timestamps.push(now);
    next();
  };
}
"}}
