{"name": "write_file", "arguments": {"path": "src/utils/deep-clone.ts", "content": "/**
 * Deep clone an object without JSON serialization.
 * Handles: plain objects, arrays, Date, RegExp, Map, Set.
 * Does NOT handle: circular references, functions, symbols, WeakMap/WeakSet.
 */
export function deepClone<T>(obj: T): T {
  if (obj === null || typeof obj !== 'object') return obj;

  if (obj instanceof Date) return new Date(obj.getTime()) as T;
  if (obj instanceof RegExp) return new RegExp(obj.source, obj.flags) as T;

  if (obj instanceof Map) {
    const map = new Map();
    for (const [key, val] of obj) {
      map.set(deepClone(key), deepClone(val));
    }
    return map as T;
  }

  if (obj instanceof Set) {
    const set = new Set();
    for (const val of obj) {
      set.add(deepClone(val));
    }
    return set as T;
  }

  if (Array.isArray(obj)) {
    return obj.map((item) => deepClone(item)) as T;
  }

  // Plain object
  const clone = Object.create(Object.getPrototypeOf(obj));
  for (const key of Object.keys(obj)) {
    clone[key] = deepClone((obj as Record<string, unknown>)[key]);
  }
  return clone;
}
"}}
