{"name": "write_file", "arguments": {"path": "src/utils/event-bus.ts", "content": "type Handler<T = unknown> = (data: T) => void;

/**
 * Type-safe event emitter / pub-sub bus.
 *
 * Usage:
 *   const bus = new EventBus<{
 *     'user:login': { userId: string };
 *     'order:placed': { orderId: string; total: number };
 *   }>();
 *
 *   bus.on('user:login', ({ userId }) => console.log(userId));
 *   bus.emit('user:login', { userId: '123' });
 */
export class EventBus<Events extends Record<string, unknown>> {
  private listeners = new Map<keyof Events, Set<Handler<any>>>();

  on<K extends keyof Events>(event: K, handler: Handler<Events[K]>): () => void {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, new Set());
    }
    this.listeners.get(event)!.add(handler);

    // Return unsubscribe function
    return () => this.off(event, handler);
  }

  once<K extends keyof Events>(event: K, handler: Handler<Events[K]>): () => void {
    const wrapper: Handler<Events[K]> = (data) => {
      handler(data);
      this.off(event, wrapper);
    };
    return this.on(event, wrapper);
  }

  off<K extends keyof Events>(event: K, handler: Handler<Events[K]>): void {
    this.listeners.get(event)?.delete(handler);
  }

  emit<K extends keyof Events>(event: K, data: Events[K]): void {
    const handlers = this.listeners.get(event);
    if (!handlers) return;
    for (const handler of handlers) {
      handler(data);
    }
  }

  removeAll(event?: keyof Events): void {
    if (event) {
      this.listeners.delete(event);
    } else {
      this.listeners.clear();
    }
  }
}
"}}
