{"name": "write_file", "arguments": {"path": "src/hooks/useForm.ts", "content": "import { useState, useCallback, type ChangeEvent, type FormEvent } from 'react';

type Validator<T> = {
  [K in keyof T]?: (value: T[K], fields: T) => string | null;
};

interface UseFormReturn<T> {
  values: T;
  errors: Partial<Record<keyof T, string>>;
  touched: Partial<Record<keyof T, boolean>>;
  handleChange: (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => void;
  handleBlur: (e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => void;
  handleSubmit: (onSubmit: (values: T) => void | Promise<void>) => (e: FormEvent) => void;
  setField: (name: keyof T, value: T[keyof T]) => void;
  reset: () => void;
  isValid: boolean;
}

export function useForm<T extends Record<string, any>>(
  initialValues: T,
  validators?: Validator<T>,
): UseFormReturn<T> {
  const [values, setValues] = useState<T>(initialValues);
  const [errors, setErrors] = useState<Partial<Record<keyof T, string>>>({});
  const [touched, setTouched] = useState<Partial<Record<keyof T, boolean>>>({});

  const validate = useCallback(
    (name: keyof T, value: T[keyof T]): string | null => {
      const validator = validators?.[name];
      return validator ? validator(value, values) : null;
    },
    [validators, values],
  );

  const validateAll = useCallback((): boolean => {
    if (!validators) return true;
    const newErrors: Partial<Record<keyof T, string>> = {};
    let valid = true;

    for (const key of Object.keys(validators) as (keyof T)[]) {
      const error = validate(key, values[key]);
      if (error) {
        newErrors[key] = error;
        valid = false;
      }
    }

    setErrors(newErrors);
    return valid;
  }, [validators, values, validate]);

  const handleChange = useCallback((e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setValues((prev) => ({ ...prev, [name]: value }));

    if (touched[name as keyof T]) {
      const error = validate(name as keyof T, value as T[keyof T]);
      setErrors((prev) => ({ ...prev, [name]: error || undefined }));
    }
  }, [touched, validate]);

  const handleBlur = useCallback((e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setTouched((prev) => ({ ...prev, [name]: true }));

    const error = validate(name as keyof T, value as T[keyof T]);
    setErrors((prev) => ({ ...prev, [name]: error || undefined }));
  }, [validate]);

  const handleSubmit = useCallback(
    (onSubmit: (values: T) => void | Promise<void>) => (e: FormEvent) => {
      e.preventDefault();
      // Touch all fields
      const allTouched = Object.keys(values).reduce(
        (acc, key) => ({ ...acc, [key]: true }),
        {} as Record<keyof T, boolean>,
      );
      setTouched(allTouched);

      if (validateAll()) {
        onSubmit(values);
      }
    },
    [values, validateAll],
  );

  const setField = useCallback((name: keyof T, value: T[keyof T]) => {
    setValues((prev) => ({ ...prev, [name]: value }));
  }, []);

  const reset = useCallback(() => {
    setValues(initialValues);
    setErrors({});
    setTouched({});
  }, [initialValues]);

  const isValid = Object.values(errors).every((e) => !e);

  return { values, errors, touched, handleChange, handleBlur, handleSubmit, setField, reset, isValid };
}
"}}
```

Created `src/hooks/useForm.ts` — a type-safe form hook with:

- **Per-field validators** — return an error string or null
- **Validate on blur** — don't annoy users while they're typing
- **Validate on change after touch** — once they've left a field, validate in real-time
- **Submit validation** — validates everything and touches all fields to show all errors
- **Generic types** — form shape is inferred from `initialValues`

Usage:
```tsx
const { values, errors, handleChange, handleBlur, handleSubmit } = useForm(
  { email: '', password: '' },
  {
    email: (v) => !v.includes('@') ? 'Invalid email' : null,
    password: (v) => v.length < 8 ? 'Min 8 characters' : null,
  },
);
```

