{"name": "write_file", "arguments": {"path": "kv-store/src/main.rs", "content": "use actix_web::{web, App, HttpServer, HttpResponse, middleware};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::sync::Mutex;

type Store = web::Data<Mutex<HashMap<String, String>>>;

#[derive(Deserialize)]
struct SetRequest {
    value: String,
}

#[derive(Serialize)]
struct GetResponse {
    key: String,
    value: String,
}

#[derive(Serialize)]
struct ErrorResponse {
    error: String,
}

async fn get_key(store: Store, path: web::Path<String>) -> HttpResponse {
    let key = path.into_inner();
    let map = store.lock().unwrap();

    match map.get(&key) {
        Some(value) => HttpResponse::Ok().json(GetResponse {
            key,
            value: value.clone(),
        }),
        None => HttpResponse::NotFound().json(ErrorResponse {
            error: format!("Key '{}' not found", key),
        }),
    }
}

async fn set_key(
    store: Store,
    path: web::Path<String>,
    body: web::Json<SetRequest>,
) -> HttpResponse {
    let key = path.into_inner();
    let mut map = store.lock().unwrap();
    let existed = map.insert(key.clone(), body.value.clone()).is_some();

    if existed {
        HttpResponse::Ok().json(serde_json::json!({
            "status": "updated",
            "key": key
        }))
    } else {
        HttpResponse::Created().json(serde_json::json!({
            "status": "created",
            "key": key
        }))
    }
}

async fn delete_key(store: Store, path: web::Path<String>) -> HttpResponse {
    let key = path.into_inner();
    let mut map = store.lock().unwrap();

    match map.remove(&key) {
        Some(_) => HttpResponse::Ok().json(serde_json::json!({
            "status": "deleted",
            "key": key
        })),
        None => HttpResponse::NotFound().json(ErrorResponse {
            error: format!("Key '{}' not found", key),
        }),
    }
}

async fn list_keys(store: Store) -> HttpResponse {
    let map = store.lock().unwrap();
    let keys: Vec<&String> = map.keys().collect();
    HttpResponse::Ok().json(serde_json::json!({
        "count": keys.len(),
        "keys": keys
    }))
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    let store: Store = web::Data::new(Mutex::new(HashMap::new()));

    println!("KV store running on http://127.0.0.1:8080");

    HttpServer::new(move || {
        App::new()
            .app_data(store.clone())
            .route("/kv", web::get().to(list_keys))
            .route("/kv/{key}", web::get().to(get_key))
            .route("/kv/{key}", web::put().to(set_key))
            .route("/kv/{key}", web::delete().to(delete_key))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}
"}}
