	Err   error
}

// ProcessFunc is the function each worker calls to process a job.
type ProcessFunc func(ctx context.Context, job Job) (any, error)

// Pool runs a fixed number of workers that pull jobs from a channel.
// Results are sent to the returned channel. The result channel is closed
// when all jobs are processed.
func Pool(ctx context.Context, workers int, jobs <-chan Job, process ProcessFunc) <-chan Result {
	results := make(chan Result, workers)
	var wg sync.WaitGroup

	for i := 0; i < workers; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			for job := range jobs {
				// Check if context is cancelled before processing
				select {
				case <-ctx.Done():
					results <- Result{JobID: job.ID, Err: ctx.Err()}
					return
				default:
				}

				value, err := process(ctx, job)
				results <- Result{JobID: job.ID, Value: value, Err: err}
			}
		}()
	}

	// Close results channel when all workers are done
	go func() {
		wg.Wait()
		close(results)
	}()

	return results
}
"}}
