import (
	"context"
	"sync"
)

type Job func(ctx context.Context) error

type Pool struct {
	workers int
	jobs    chan Job
	wg      sync.WaitGroup
	errors  []error
	mu      sync.Mutex
}

func New(workers int) *Pool {
	return &Pool{workers: workers, jobs: make(chan Job, workers*2)}
}

func (p *Pool) Start(ctx context.Context) {
	for i := 0; i < p.workers; i++ {
		go func() {
			for job := range p.jobs {
				if err := job(ctx); err != nil {
					p.mu.Lock()
					p.errors = append(p.errors, err)
					p.mu.Unlock()
				}
				p.wg.Done()
			}
		}()
	}
}

func (p *Pool) Submit(job Job) {
	p.wg.Add(1)
	p.jobs <- job
}

func (p *Pool) Wait() []error {
	close(p.jobs)
	p.wg.Wait()
	return p.errors
}
