use thiserror::Error;

#[derive(Debug)]
pub struct Record {
    pub fields: Vec<String>,
}

#[derive(Debug, Error)]
pub enum CsvError {
    #[error("IO error: {0}")]
    Io(#[from] std::io::Error),
    #[error("Parse error on line {line}: {message}")]
    Parse { line: usize, message: String },
}

pub fn read_csv(path: &Path) -> Result<Vec<Record>, CsvError> {
    let file = File::open(path)?;  // ? converts io::Error via From impl
    let reader = BufReader::new(file);
    let mut records = Vec::new();

    for (i, line) in reader.lines().enumerate() {
        let line = line?;
        if line.trim().is_empty() || line.starts_with('#') {
            continue;
        }
        let fields: Vec<String> = line
            .split(',')
            .map(|f| f.trim().to_string())
            .collect();
        if fields.is_empty() {
            return Err(CsvError::Parse { line: i + 1, message: "empty record".into() });
        }
        records.push(Record { fields });
    }

    Ok(records)
}
