  'user:login': { userId: string; ip: string };
  'order:placed': { orderId: string; total: number };
};

const bus = new TypedEmitter<AppEvents>();
bus.emit('user:login', { userId: '123', ip: '1.2.3.4' }); // OK
bus.emit('user:login', { userId: '123' }); // TS error: missing 'ip'
```

The `on()` method returns an unsubscribe function — this pattern avoids the common bug of passing different function references to `on` and `off` which means `off` silently does nothing.

