      case 'PlaceOrder': {
        const order = Order.create(cmd.customerId, cmd.items);
        await this.repo.save(order);
        await this.events.publish({ type: 'OrderPlaced', orderId: order.id, customerId: cmd.customerId });
        return { orderId: order.id };
      }
      case 'CancelOrder': {
        const order = await this.repo.findById(cmd.orderId);
        if (!order) throw new Error('Order not found');
        order.cancel(cmd.reason);
        await this.repo.save(order);
        await this.events.publish({ type: 'OrderCancelled', orderId: cmd.orderId, reason: cmd.reason });
        return { orderId: cmd.orderId };
      }
    }
  }
}
