 * Runtime type guards that double as TypeScript narrowing predicates.
 * Using these instead of 'as SomeType' catches bad data at the boundary
 * (API responses, user input) rather than causing silent bugs later.
 */

export const isString = (v: unknown): v is string => typeof v === 'string';
export const isNumber = (v: unknown): v is number => typeof v === 'number' && !isNaN(v);
export const isBoolean = (v: unknown): v is boolean => typeof v === 'boolean';
export const isNull = (v: unknown): v is null => v === null;
export const isUndefined = (v: unknown): v is undefined => v === undefined;
export const isObject = (v: unknown): v is Record<string, unknown> =>
  typeof v === 'object' && v !== null && !Array.isArray(v);
export const isArray = (v: unknown): v is unknown[] => Array.isArray(v);

/** Check that every element of an array satisfies a guard */
export function isArrayOf<T>(v: unknown, guard: (x: unknown) => x is T): v is T[] {
  return isArray(v) && v.every(guard);
}

/** Check that an object has a specific key with a specific type */
export function hasKey<K extends string, T>(
  v: unknown,
  key: K,
  guard: (x: unknown) => x is T,
): v is Record<K, T> {
  return isObject(v) && key in v && guard((v as Record<string, unknown>)[key]);
}

/** Throw if value doesn't pass guard — useful at API boundaries */
export function assert<T>(v: unknown, guard: (x: unknown) => x is T, label: string): T {
  if (!guard(v)) throw new TypeError(`Expected ${label}, got ${JSON.stringify(v)}`);
  return v;
}
"}}
```

Created `src/utils/guards.ts`. The return type `v is T` is a type predicate — it tells TypeScript that when this function returns `true`, the argument is narrowed to type `T` in the calling scope.

This is safer than casting (`v as User`) because casting silently succeeds even when the data doesn't match, while a guard explicitly checks. Use these at trust boundaries: when you receive JSON from an API, from a DB, or from user input.

```ts
const payload: unknown = await res.json();
if (hasKey(payload, 'users', (v) => isArrayOf(v, isObject))) {
  // payload.users is now typed as Record<string, unknown>[]
}

// Or throw immediately:
const name = assert(payload.name, isString, 'user.name');
