{"name":"write_file","arguments":{"path":"src/db/pool.ts","content":"import { Pool, PoolConfig } from 'pg';

let pool: Pool | null = null;

/**
 * Returns the singleton pool instance.
 * Lazy initialization — pool is created on first use, not at module load time.
 */
export function getPool(): Pool {
  if (!pool) {
    const config: PoolConfig = {
      connectionString: process.env.DATABASE_URL,
      max: 20,              // max connections in pool
      idleTimeoutMillis: 30_000,  // close idle clients after 30s
      connectionTimeoutMillis: 2_000, // fail fast if no connection available
      ssl: process.env.NODE_ENV === 'production' ? { rejectUnauthorized: true } : false,
    };
    pool = new Pool(config);

    pool.on('error', (err) => {
      // pg emits errors on idle clients — log them but don't crash
      console.error('Unexpected pool error', err);
    });
  }
  return pool;
}

/** Run a query and automatically return the client to the pool */
export async function query<T = unknown>(sql: string, params?: unknown[]): Promise<T[]> {
  const result = await getPool().query(sql, params);
  return result.rows as T[];
}

/** Run multiple queries in a transaction, rolling back on error */
export async function withTransaction<T>(fn: (client: import('pg').PoolClient) => Promise<T>): Promise<T> {
  const client = await getPool().connect();
  try {
    await client.query('BEGIN');
    const result = await fn(client);
    await client.query('COMMIT');
    return result;
  } catch (err) {
    await client.query('ROLLBACK');
    throw err;
  } finally {
    client.release(); // ALWAYS release, even on error
  }
}

/** Graceful shutdown — drain connections before process exit */
export async function closePool(): Promise<void> {
  if (pool) {
    await pool.end();
    pool = null;
  }
}
"}}
