{"name":"write_file","arguments":{"path":"src/middleware/cors.ts","content":"import { Request, Response, NextFunction } from 'express';

interface CorsOptions {
  origins: string[] | '*';
  methods?: string[];
  allowedHeaders?: string[];
  credentials?: boolean;
  maxAgeSeconds?: number;
}

export function cors(opts: CorsOptions) {
  const methods = opts.methods ?? ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'];
  const headers = opts.allowedHeaders ?? ['Content-Type', 'Authorization'];

  return (req: Request, res: Response, next: NextFunction) => {
    const origin = req.headers.origin;

    // Determine if this origin is allowed
    if (opts.origins === '*') {
      res.setHeader('Access-Control-Allow-Origin', '*');
    } else if (origin && opts.origins.includes(origin)) {
      res.setHeader('Access-Control-Allow-Origin', origin);
      // Vary tells CDNs this response differs per Origin header
      res.setHeader('Vary', 'Origin');
    }

    if (opts.credentials) {
      // credentials:true requires an explicit origin, not wildcard
      res.setHeader('Access-Control-Allow-Credentials', 'true');
    }

    // Preflight request — browser asks permission before the real request
    if (req.method === 'OPTIONS') {
      res.setHeader('Access-Control-Allow-Methods', methods.join(', '));
      res.setHeader('Access-Control-Allow-Headers', headers.join(', '));
      if (opts.maxAgeSeconds) {
        res.setHeader('Access-Control-Max-Age', String(opts.maxAgeSeconds));
      }
      return res.status(204).end();
    }

    next();
  };
}
