import { join } from 'path';
import { db } from './connection';

interface Migration {
  version: number;
  name: string;
  up: string;
  down: string;
}

async function ensureMigrationsTable() {
  await db.run(`
    CREATE TABLE IF NOT EXISTS schema_migrations (
      version  INTEGER PRIMARY KEY,
      name     TEXT NOT NULL,
      applied_at TEXT NOT NULL
    )
  `);
}

async function loadMigrations(dir: string): Promise<Migration[]> {
  const files = (await readdir(dir)).filter(f => f.endsWith('.sql')).sort();
  return Promise.all(files.map(async (file) => {
    const content = await readFile(join(dir, file), 'utf8');
    const [up = '', down = ''] = content.split('-- DOWN');
    const match = file.match(/^(\d+)_(.+)\.sql$/);
    if (!match) throw new Error('Migration filename must be NNN_name.sql: ' + file);
    return { version: Number(match[1]), name: match[2], up: up.replace('-- UP', '').trim(), down: down.trim() };
  }));
}

export async function migrateUp(dir = 'db/migrations') {
  await ensureMigrationsTable();
  const migrations = await loadMigrations(dir);
  const applied = new Set((await db.all('SELECT version FROM schema_migrations')).map((r: any) => r.version));

  for (const m of migrations) {
    if (applied.has(m.version)) continue;
    console.log(`Applying migration ${m.version}: ${m.name}`);
    await db.run('BEGIN');
    try {
      await db.exec(m.up);
      await db.run('INSERT INTO schema_migrations VALUES (?,?,?)', [m.version, m.name, new Date().toISOString()]);
      await db.run('COMMIT');
    } catch (err) {
      await db.run('ROLLBACK');
      throw new Error('Migration ' + m.version + ' failed: ' + err);
    }
  }
  console.log('All migrations applied');
}

export async function migrateDown(dir = 'db/migrations', steps = 1) {
  await ensureMigrationsTable();
  const migrations = await loadMigrations(dir);
  const applied = await db.all('SELECT version FROM schema_migrations ORDER BY version DESC LIMIT ?', [steps]);

  for (const row of applied as any[]) {
    const m = migrations.find(m => m.version === row.version);
    if (!m) throw new Error('Migration file not found for version ' + row.version);
    console.log(`Reverting migration ${m.version}: ${m.name}`);
    await db.exec(m.down);
    await db.run('DELETE FROM schema_migrations WHERE version=?', [m.version]);
  }
}
"}}
