import { z, ZodSchema, ZodError } from 'zod';

/**
 * Middleware factory — pass a Zod schema for body, query, or params.
 * On failure returns 422 with field-level errors; on success attaches parsed data.
 */
export function validate<T extends { body?: ZodSchema; query?: ZodSchema; params?: ZodSchema }>(schemas: T) {
  return (req: Request, res: Response, next: NextFunction) => {
    try {
      if (schemas.body) req.body = schemas.body.parse(req.body);
      if (schemas.query) req.query = schemas.query.parse(req.query) as any;
      if (schemas.params) req.params = schemas.params.parse(req.params) as any;
      next();
    } catch (err) {
      if (err instanceof ZodError) {
        return res.status(422).json({
          error: 'Validation failed',
          fields: err.errors.map(e => ({
            path: e.path.join('.'),
            message: e.message,
          })),
        });
      }
      next(err);
    }
  };
}

// Example schemas co-located here for documentation
export const CreateUserSchema = z.object({
  name: z.string().min(1).max(200).trim(),
  email: z.string().email().toLowerCase(),
  age: z.number().int().min(13).max(150).optional(),
  role: z.enum(['user', 'admin']).default('user'),
});

export type CreateUserInput = z.infer<typeof CreateUserSchema>;
"}}
