{"name":"write_file","arguments":{"path":"src/hooks/useAsync.ts","content":"import { useState, useEffect, useCallback, useRef } from 'react';

interface AsyncState<T> {
  data: T | null;
  loading: boolean;
  error: Error | null;
}

/**
 * useAsync — run an async function, track its state.
 * Re-runs when dependencies change (like useEffect).
 */
export function useAsync<T>(
  fn: () => Promise<T>,
  deps: React.DependencyList,
): AsyncState<T> & { refetch: () => void } {
  const [state, setState] = useState<AsyncState<T>>({ data: null, loading: true, error: null });
  const counter = useRef(0); // tracks latest invocation to prevent stale updates

  const run = useCallback(() => {
    const id = ++counter.current;
    setState(s => ({ ...s, loading: true, error: null }));
    fn().then(
      data => { if (counter.current === id) setState({ data, loading: false, error: null }); },
      error => { if (counter.current === id) setState({ data: null, loading: false, error }); }
    );
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, deps);

  useEffect(() => { run(); }, [run]);

  return { ...state, refetch: run };
}

/**
 * useMutation — for write operations triggered by user action.
 * Does not auto-run; call mutate() explicitly.
 */
export function useMutation<TArgs extends unknown[], TResult>(
  fn: (...args: TArgs) => Promise<TResult>,
) {
  const [state, setState] = useState<AsyncState<TResult>>({ data: null, loading: false, error: null });

  const mutate = useCallback(async (...args: TArgs) => {
    setState({ data: null, loading: true, error: null });
    try {
      const data = await fn(...args);
      setState({ data, loading: false, error: null });
      return data;
    } catch (error) {
      setState({ data: null, loading: false, error: error as Error });
      throw error; // re-throw so callers can chain .catch()
    }
  }, [fn]);

  return { ...state, mutate };
}
"}}
