{"name":"write_file","arguments":{"path":"src/container.ts","content":"type Constructor<T> = new (...args: any[]) => T;
type Factory<T> = () => T;
type Token<T> = string | symbol | Constructor<T>;

interface Binding<T> {
  factory: Factory<T>;
  singleton: boolean;
  instance?: T;
}

export class Container {
  private bindings = new Map<Token<unknown>, Binding<unknown>>();

  /** Register a class — resolved by calling new Class(...deps) */
  bind<T>(token: Token<T>, factory: Factory<T>, singleton = true): this {
    this.bindings.set(token, { factory, singleton });
    return this;
  }

  /** Register a pre-constructed value (always singleton) */
  instance<T>(token: Token<T>, value: T): this {
    this.bindings.set(token, { factory: () => value, singleton: true, instance: value });
    return this;
  }

  resolve<T>(token: Token<T>): T {
    const binding = this.bindings.get(token) as Binding<T> | undefined;
    if (!binding) {
      throw new Error(`No binding found for token: ${String(token)}`);
    }
    if (binding.singleton) {
      if (binding.instance === undefined) {
        binding.instance = binding.factory();
      }
      return binding.instance;
    }
    return binding.factory();
  }
}

