 * Generic middleware pipeline.
 * Each middleware receives context and a `next` function to call the next step.
 * This is the same pattern Express uses, but typed and framework-agnostic.
 */

type Next = () => Promise<void>;
type Middleware<T> = (ctx: T, next: Next) => Promise<void>;

export function compose<T>(middlewares: Middleware<T>[]): Middleware<T> {
  return async (ctx: T, next: Next) => {
    let index = -1;

    async function dispatch(i: number): Promise<void> {
      if (i <= index) throw new Error('next() called multiple times');
      index = i;
      const fn = i < middlewares.length ? middlewares[i] : next;
      await fn(ctx, () => dispatch(i + 1));
    }

    return dispatch(0);
  };
}

// Example: request processing pipeline
interface RequestCtx {
  path: string;
  headers: Record<string, string>;
  body: unknown;
  response?: unknown;
  userId?: string;
  startTime?: number;
}

const logger: Middleware<RequestCtx> = async (ctx, next) => {
  ctx.startTime = Date.now();
  await next();
  console.log(`${ctx.path} → ${Date.now() - ctx.startTime!}ms`);
};

const auth: Middleware<RequestCtx> = async (ctx, next) => {
  const token = ctx.headers['authorization']?.slice(7);
  if (!token) throw new Error('Unauthorized');
  ctx.userId = verifyToken(token); // populates ctx for downstream
  await next();
};

const pipeline = compose([logger, auth]);
