{"name":"write_file","arguments":{"path":"src/utils/deep-merge.ts","content":"/**
 * Deep merge objects. Later sources overwrite earlier ones for primitives;
 * plain objects are merged recursively. Arrays are replaced, not concatenated.
 */
export function deepMerge<T extends object>(...sources: Partial<T>[]): T {
  const result: Record<string, unknown> = {};

  for (const source of sources) {
    if (!source || typeof source !== 'object') continue;
    for (const [key, value] of Object.entries(source)) {
      const existing = result[key];
      if (isPlainObject(value) && isPlainObject(existing)) {
        result[key] = deepMerge(existing, value);
      } else if (value !== undefined) {
        result[key] = value;
      }
    }
