export function useOptimistic<T>(initial: T) {
  const [state, setState] = useState<T>(initial);
  const [pending, setPending] = useState(false);
  const [error, setError] = useState<Error | null>(null);

  const optimisticUpdate = useCallback(async (
    optimisticValue: T,
    mutation: () => Promise<T>,
  ) => {
    const previous = state;
    setState(optimisticValue);
    setPending(true);
    setError(null);
    try {
      const confirmed = await mutation();
      setState(confirmed);
    } catch (err) {
      setState(previous);
      setError(err as Error);
      throw err;
    } finally {
      setPending(false);
    }
  }, [state]);

  return { state, setState, optimisticUpdate, pending, error };
}
"}}
```

Created `src/hooks/useOptimistic.ts`. The pattern: save `previous` before updating, apply the optimistic value immediately, then either confirm with the server response or restore `previous` on failure.

The mutation returns `T` (the confirmed value) because the server might return a slightly different object (e.g., with a server-generated `updatedAt` timestamp). You apply the server version on success rather than keeping the optimistic one.

```ts
const { state: todos, optimisticUpdate } = useOptimistic(initialTodos);
async function toggleTodo(id: string) {
  const updated = todos.map(t => t.id === id ? { ...t, done: !t.done } : t);
  await optimisticUpdate(updated, () => api.toggleTodo(id));
}
