{"name":"write_file","arguments":{"path":"src/messaging/broker.ts","content":"export interface Message<T = unknown> {
  id: string;
  topic: string;
  payload: T;
  timestamp: number;
}

type Handler<T> = (msg: Message<T>) => Promise<void> | void;

export class MessageBroker {
  private subs = new Map<string, Set<Handler<unknown>>>();
  private deadLetters: Message<unknown>[] = [];

  subscribe<T>(topic: string, handler: Handler<T>): () => void {
    if (!this.subs.has(topic)) this.subs.set(topic, new Set());
    this.subs.get(topic)!.add(handler as Handler<unknown>);
    return () => this.subs.get(topic)?.delete(handler as Handler<unknown>);
  }

  async publish<T>(topic: string, payload: T): Promise<void> {
    const msg: Message<T> = { id: crypto.randomUUID(), topic, payload, timestamp: Date.now() };
    const handlers = this.subs.get(topic);
    if (!handlers?.size) {
      this.deadLetters.push(msg);
      return;
    }
    const results = await Promise.allSettled([...handlers].map(h => h(msg)));
    const failed = results.filter(r => r.status === 'rejected');
    if (failed.length) {
      console.error(failed.length + ' handler(s) failed for topic ' + topic);
    }
  }

  getDeadLetters() { return [...this.deadLetters]; }
}

export const broker = new MessageBroker();
