const LEVELS: Record<Level, number> = { debug: 0, info: 1, warn: 2, error: 3 };
const minLevel: Level = (process.env.LOG_LEVEL as Level) ?? 'info';
const isProd = process.env.NODE_ENV === 'production';

function log(level: Level, message: string, fields?: Record<string, unknown>): void {
  if (LEVELS[level] < LEVELS[minLevel]) return;
  const entry = {
    timestamp: new Date().toISOString(),
    level,
    message,
    ...fields,
    pid: process.pid,
    service: process.env.SERVICE_NAME ?? 'app',
  };
  if (isProd) {
    const out = JSON.stringify(entry);
    (level === 'error' ? console.error : console.log)(out);
  } else {
    const colors: Record<Level, string> = { debug: '\x1b[90m', info: '\x1b[36m', warn: '\x1b[33m', error: '\x1b[31m' };
    const extra = fields ? ' ' + JSON.stringify(fields) : '';
    console.log(colors[level] + '[' + level.toUpperCase() + '] ' + message + extra + '\x1b[0m');
  }
}

