{"name":"write_file","arguments":{"path":"src/utils/http.ts","content":"export interface RequestOptions extends Omit<RequestInit, 'body'> {
  params?: Record<string, string | number | boolean>;
  json?: unknown;
  timeoutMs?: number;
}

export class HttpError extends Error {
  constructor(public readonly status: number, public readonly body: unknown, public readonly url: string) {
    super('HTTP ' + status + ' ' + url);
  }
}

async function request<T>(url: string, opts: RequestOptions = {}): Promise<T> {
  const { params, json, timeoutMs = 30_000, ...init } = opts;

  const fullUrl = params
    ? url + '?' + new URLSearchParams(Object.fromEntries(Object.entries(params).map(([k, v]) => [k, String(v)])))
    : url;

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);

  try {
    const res = await fetch(fullUrl, {
      ...init,
      signal: controller.signal,
      headers: { 'Content-Type': 'application/json', ...init.headers },
      body: json !== undefined ? JSON.stringify(json) : init.body,
    });
    const data: unknown = await res.json().catch(() => null);
    if (!res.ok) throw new HttpError(res.status, data, fullUrl);
    return data as T;
  } finally {
    clearTimeout(timer);
  }
}

export const http = {
  get:    <T>(url: string, opts?: RequestOptions) => request<T>(url, { method: 'GET', ...opts }),
  post:   <T>(url: string, json: unknown, opts?: RequestOptions) => request<T>(url, { method: 'POST', json, ...opts }),
  put:    <T>(url: string, json: unknown, opts?: RequestOptions) => request<T>(url, { method: 'PUT', json, ...opts }),
  patch:  <T>(url: string, json: unknown, opts?: RequestOptions) => request<T>(url, { method: 'PATCH', json, ...opts }),
  delete: <T>(url: string, opts?: RequestOptions) => request<T>(url, { method: 'DELETE', ...opts }),
};
"}}
