/**
 * Soft delete: records are never physically removed.
 * deleted_at is null for active records, a timestamp for deleted ones.
 * This preserves audit trails and foreign key integrity.
 */
export abstract class SoftDeleteRepository<T extends { id: string }> {
  abstract readonly tableName: string;

  async findById(id: string): Promise<T | null> {
    const row = await db.get(
      'SELECT * FROM ' + this.tableName + ' WHERE id = ? AND deleted_at IS NULL',
      [id]
    );
    return row ? this.mapRow(row) : null;
  }

  async findAll(): Promise<T[]> {
    const rows = await db.all(
      'SELECT * FROM ' + this.tableName + ' WHERE deleted_at IS NULL ORDER BY created_at DESC'
    );
    return rows.map(r => this.mapRow(r));
  }

  async delete(id: string): Promise<boolean> {
    const result = await db.run(
      'UPDATE ' + this.tableName + ' SET deleted_at = ? WHERE id = ? AND deleted_at IS NULL',
      [new Date().toISOString(), id]
    );
    return (result.changes ?? 0) > 0;
  }

  async restore(id: string): Promise<boolean> {
    const result = await db.run(
      'UPDATE ' + this.tableName + ' SET deleted_at = NULL WHERE id = ?',
      [id]
    );
    return (result.changes ?? 0) > 0;
  }

  async findDeleted(): Promise<T[]> {
    const rows = await db.all(
      'SELECT * FROM ' + this.tableName + ' WHERE deleted_at IS NOT NULL ORDER BY deleted_at DESC'
    );
    return rows.map(r => this.mapRow(r));
  }

  protected abstract mapRow(row: Record<string, unknown>): T;
}
"}}
