// Sentinel errors — use errors.Is() to check, never string comparison
var (
	ErrNotFound   = errors.New("not found")
	ErrUnauthorized = errors.New("unauthorized")
	ErrConflict   = errors.New("conflict")
	ErrBadRequest = errors.New("bad request")
)

// DomainError wraps a sentinel with context.
// Use %w in fmt.Errorf so errors.Is() unwraps through the chain.
type DomainError struct {
	Code    string
	Message string
	Cause   error
}

func (e *DomainError) Error() string {
	if e.Cause != nil {
		return fmt.Sprintf("%s: %v", e.Message, e.Cause)
	}
	return e.Message
}

func (e *DomainError) Unwrap() error { return e.Cause }

func NotFound(resource, id string) error {
	return &DomainError{Code: "NOT_FOUND", Message: resource + " not found: " + id, Cause: ErrNotFound}
}

func Unauthorized(reason string) error {
	return &DomainError{Code: "UNAUTHORIZED", Message: reason, Cause: ErrUnauthorized}
}

// WrapDB wraps a database error with context without losing the original
func WrapDB(err error, op string) error {
	if err == nil { return nil }
	return fmt.Errorf("%s: %w", op, err)
}
