 * Recursively freeze an object and all nested objects.
 * TypeScript's 'as const' and 'Readonly' are compile-time only — this enforces it at runtime too.
 * Useful for config objects that should never be mutated after creation.
 */

type DeepReadonly<T> =
  T extends (infer U)[]
    ? ReadonlyArray<DeepReadonly<U>>
    : T extends object
    ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
    : T;

export function deepFreeze<T extends object>(obj: T): DeepReadonly<T> {
  // Freeze own properties first
  Object.getOwnPropertyNames(obj).forEach(name => {
    const value = (obj as Record<string, unknown>)[name];
    if (value !== null && typeof value === 'object' && !Object.isFrozen(value)) {
      deepFreeze(value as object);
    }
  });
  return Object.freeze(obj) as DeepReadonly<T>;
}

// Example: config that can never be accidentally mutated
export const CONFIG = deepFreeze({
  api: {
    baseUrl: 'https://api.example.com',
    timeout: 5000,
    retries: 3,
