import { logger } from '../logger';

export function startPoolHealthMonitor(pool: Pool, intervalMs = 30_000) {
  // pg emits this when a client errors in the pool's idle queue
  pool.on('error', (err, client) => {
    logger.error('Idle pool client error', { error: err.message });
    // The pool automatically removes the bad client and creates a replacement
  });

  // Periodic health probe — acquire a connection and test it
  const timer = setInterval(async () => {
    const client = await pool.connect().catch(err => {
      logger.error('Pool health check: failed to acquire connection', { error: err.message });
      return null;
    });

    if (!client) return;

    try {
      await client.query('SELECT 1');
      const stats = {
        total: pool.totalCount,
        idle: pool.idleCount,
        waiting: pool.waitingCount,
      };
      if (stats.waiting > 5) {
        logger.warn('Connection pool under pressure', stats);
      } else {
        logger.debug('Pool health OK', stats);
      }
    } catch (err) {
      logger.error('Pool health check query failed', { error: String(err) });
    } finally {
      client.release();
    }
  }, intervalMs);

  // Return a stop function for clean shutdown
  return () => clearInterval(timer);
}
