{"name":"write_file","arguments":{"path":"src/utils/observable.ts","content":"export class Observable<T> {
  private observers: Set<(value: T) => void> = new Set();
  private _value: T;

  constructor(initialValue: T) {
    this._value = initialValue;
  }

  get value(): T { return this._value; }

  set(newValue: T): void {
    if (newValue === this._value) return;
    this._value = newValue;
    this.notify();
  }

  update(fn: (current: T) => T): void { this.set(fn(this._value)); }

  subscribe(observer: (value: T) => void): () => void {
    this.observers.add(observer);
    observer(this._value); // emit current value on subscribe
    return () => this.observers.delete(observer);
  }

  private notify(): void { this.observers.forEach(o => o(this._value)); }
}

export function derived<T, U>(source: Observable<T>, fn: (v: T) => U): Observable<U> {
  const result = new Observable<U>(fn(source.value));
  source.subscribe(v => result.set(fn(v)));
  return result;
}
"}}
