{"content":"export interface OrderItem { productId: string; qty: number; unitCents: number; }
export interface Order { id: string; items: OrderItem[]; discountCents?: number; }
export interface OrderSummary { subtotalCents: number; discountCents: number; totalCents: number; itemCount: number; }

export function summarizeOrder(order: Order): OrderSummary {
  const subtotalCents = order.items.reduce((sum, i) => sum + i.qty * i.unitCents, 0);
  const discountCents = order.discountCents ?? 0;
  return {
    subtotalCents,
    discountCents,
    totalCents: Math.max(0, subtotalCents - discountCents),
    itemCount: order.items.reduce((sum, i) => sum + i.qty, 0),
  };
}
