type FlagMap = Record<string, FlagConfig>;

export class FeatureFlags {
  private flags: FlagMap;

  constructor(flags: FlagMap) { this.flags = flags; }

  isEnabled(flagName: string, userId?: string): boolean {
    const flag = this.flags[flagName];
    if (!flag || !flag.enabled) return false;

    if (userId) {
      if (flag.blocklist?.includes(userId)) return false;
      if (flag.allowlist?.includes(userId)) return true;
    }

    if (flag.rolloutPercent !== undefined && userId) {
      return stableHash(userId + flagName) % 100 < flag.rolloutPercent;
    }

    return true;
  }

  getAll(userId?: string): Record<string, boolean> {
    return Object.fromEntries(
      Object.keys(this.flags).map(name => [name, this.isEnabled(name, userId)])
    );
  }
}

function stableHash(str: string): number {
  let hash = 2166136261;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash * 16777619) >>> 0;
  }
  return hash;
}
