class QueryBuilder:
    def __init__(self, table: str):
        self._table = table
        self._conditions: list[str] = []
        self._params: list[Any] = []
        self._columns: list[str] = []
        self._order: str | None = None
        self._limit_val: int | None = None
        self._offset_val: int | None = None

    def select(self, *columns: str) -> 'QueryBuilder':
        self._columns = list(columns)
        return self

    def where(self, condition: str, *values: Any) -> 'QueryBuilder':
        self._conditions.append(condition)
        self._params.extend(values)
        return self

    def order_by(self, column: str, direction: str = 'ASC') -> 'QueryBuilder':
        direction = 'DESC' if direction.upper() == 'DESC' else 'ASC'
        self._order = self._quote(column) + ' ' + direction
        return self

    def limit(self, n: int) -> 'QueryBuilder':
        self._limit_val = int(n)
        return self

    def offset(self, n: int) -> 'QueryBuilder':
        self._offset_val = int(n)
        return self

    def build(self) -> tuple[str, list[Any]]:
        cols = ', '.join(self._quote(c) for c in self._columns) if self._columns else '*'
        sql = 'SELECT ' + cols + ' FROM ' + self._quote(self._table)
        params = list(self._params)
        if self._conditions:
            sql += ' WHERE ' + ' AND '.join(self._conditions)
        if self._order:
            sql += ' ORDER BY ' + self._order
        if self._limit_val is not None:
            sql += ' LIMIT ?'
            params.append(self._limit_val)
        if self._offset_val is not None:
            sql += ' OFFSET ?'
            params.append(self._offset_val)
        return sql, params

    def execute(self, conn) -> list:
        sql, params = self.build()
        return conn.execute(sql, params).fetchall()

    @staticmethod
    def _quote(identifier: str) -> str:
        safe = identifier.replace('`', '').replace('"', '').replace("'", '')
        return '"' + safe + '"'"}}
